def count_distinct_pairs(nums, target):
    if not nums:
        return 0

    seen = set()
    pairs = set()

    for num in nums:
        complement = target - num
        if complement in seen and (complement, num) not in pairs and (num, complement) not in pairs:
            pairs.add((min(num, complement), max(num, complement)))
        seen.add(num)

    return len(pairs)
